INSERT INTO commentaire_cr (id, compte_rendu_id, auteur_id, contenu) VALUES
    ('c0200000-0000-0000-0000-000000000001', 'f6000000-0000-0000-0000-000000000002', 'd1000000-0000-0000-0000-000000000020', 'Bien Daniel ! Ta régularité dans la lecture de Marc est encourageante. Continue à approfondir.'),
    ('c0200000-0000-0000-0000-000000000002', 'f6000000-0000-0000-0000-000000000005', 'd1000000-0000-0000-0000-000000000020', 'Excellent parcours de Marc ! La passion et la résurrection sont au coeur de notre foi.'),
    ('c0200000-0000-0000-0000-000000000003', 'f5000000-0000-0000-0000-000000000001', 'd1000000-0000-0000-0000-000000000020', 'Paul, la prière est le fondement. Luc 11 est un passage clé. Continue ainsi !'),
    ('c0200000-0000-0000-0000-000000000004', 'f5000000-0000-0000-0000-000000000002', 'd1000000-0000-0000-0000-000000000020', 'Le jeûne et la Pentecôte - quelle combinaison puissante ! Sois béni.') ON CONFLICT DO NOTHING;
INSERT INTO commentaire_cr (id, compte_rendu_id, auteur_id, contenu) VALUES
    ('c0200000-0000-0000-0000-000000000010', 'f5000000-0000-0000-0000-000000000031', 'd1000000-0000-0000-0000-000000000021', 'Lucas, Jean 6 et le jeûne - tu nourris ton âme du vrai pain. Bravo !'),
    ('c0200000-0000-0000-0000-000000000011', 'f5000000-0000-0000-0000-000000000040', 'd1000000-0000-0000-0000-000000000021', 'Emma, la parabole de la brebis perdue nous rappelle l amour de Dieu. Bel effort.'),
    ('c0200000-0000-0000-0000-000000000012', 'f5000000-0000-0000-0000-000000000041', 'd1000000-0000-0000-0000-000000000021', 'Le bon Samaritain - un modèle pour nous tous. Continue ta marche avec le Seigneur.') ON CONFLICT DO NOTHING;
INSERT INTO commentaire_cr (id, compte_rendu_id, auteur_id, contenu) VALUES
    ('c0200000-0000-0000-0000-000000000020', 'f5000000-0000-0000-0000-000000000051', 'd1000000-0000-0000-0000-000000000022', 'Nathan, Hébreux 12 et la persévérance ! Ton jeûne montre ta consécration.'),
    ('c0200000-0000-0000-0000-000000000021', 'f5000000-0000-0000-0000-000000000050', 'd1000000-0000-0000-0000-000000000022', 'Les héros de la foi dans Hébreux 11 - un chapitre inspirant. Bien !') ON CONFLICT DO NOTHING;
INSERT INTO commentaire_cr (id, compte_rendu_id, auteur_id, contenu) VALUES
    ('c0200000-0000-0000-0000-000000000030', 'f5000000-0000-0000-0000-000000000060', 'd1000000-0000-0000-0000-000000000023', 'Camille, 1 Corinthiens 13 est le chapitre de l amour par excellence. Belle méditation.'),
    ('c0200000-0000-0000-0000-000000000031', 'f5000000-0000-0000-0000-000000000061', 'd1000000-0000-0000-0000-000000000023', 'Trésor dans des vases d argile - quelle vérité profonde ! Le jeûne fortifie ta foi.') ON CONFLICT DO NOTHING;
INSERT INTO commentaire_cr (id, compte_rendu_id, auteur_id, contenu) VALUES
    ('c0200000-0000-0000-0000-000000000040', 'f5000000-0000-0000-0000-000000000070', 'd1000000-0000-0000-0000-000000000024', 'David, la hardiesse des apôtres dans Actes 4 est un modèle pour notre évangélisation ici à Douala.'),
    ('c0200000-0000-0000-0000-000000000041', 'f5000000-0000-0000-0000-000000000071', 'd1000000-0000-0000-0000-000000000024', 'Nuit de prière et 6 personnes évangélisées ! Le Seigneur agit puissamment à travers toi.'),
    ('c0200000-0000-0000-0000-000000000042', 'f5000000-0000-0000-0000-000000000080', 'd1000000-0000-0000-0000-000000000024', 'Esther, le mariage chrétien selon Éphésiens 5 est un enseignement fondamental. Bien.'),
    ('c0200000-0000-0000-0000-000000000043', 'f5000000-0000-0000-0000-000000000081', 'd1000000-0000-0000-0000-000000000024', 'L humilité de Christ dans Philippiens 2 est notre modèle. Ton jeûne est un sacrifice agréable.') ON CONFLICT DO NOTHING;
